import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

public class XSSFixedCode {

    public static void main(String[] args) {
        // Simulating user input being passed directly to the response
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Encoding user input using ESAPI to prevent XSS attacks
        HTMLEntityCodec codec = new HTMLEntityCodec();
        String encodedInput = codec.encodeForHTML(userInput);

        // Output sanitized user input in the response
        System.out.println("Welcome, " + encodedInput);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
